"use strict";(globalThis.webpackChunkluo_knowledgebase=globalThis.webpackChunkluo_knowledgebase||[]).push([[490],{9334(e,n,i){i.r(n),i.d(n,{assets:()=>l,contentTitle:()=>o,default:()=>g,frontMatter:()=>s,metadata:()=>t,toc:()=>d});const t=JSON.parse('{"id":"helios/productfiche","title":"Productfiche Helios","description":"Helios koppelt de zonnepanelen, thuisbatterij en laadpaal en laat ze samenwerken. Door realtime voorspellingen van zonneproductie en energieverbruik te combineren met actuele prijsdata, zorgt Helios ervoor dat jouw winst altijd wordt gemaximaliseerd \u2014 zonder dat je er zelf naar om hoeft tekijken","source":"@site/docs/helios/productfiche.md","sourceDirName":"helios","slug":"/helios/productfiche","permalink":"/helios/productfiche","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"title":"Productfiche Helios","sidebar_position":2},"sidebar":"tutorialSidebar","previous":{"title":"Introductie","permalink":"/"},"next":{"title":"Hardware Installatie","permalink":"/category/hardware-installatie"}}');var r=i(4848),a=i(8453);const s={title:"Productfiche Helios",sidebar_position:2},o="Productfiche Helios",l={},d=[];function c(e){const n={a:"a",admonition:"admonition",h1:"h1",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.header,{children:(0,r.jsx)(n.h1,{id:"productfiche-helios",children:"Productfiche Helios"})}),"\n",(0,r.jsx)(n.p,{children:"Helios koppelt de zonnepanelen, thuisbatterij en laadpaal en laat ze samenwerken. Door realtime voorspellingen van zonneproductie en energieverbruik te combineren met actuele prijsdata, zorgt Helios ervoor dat jouw winst altijd wordt gemaximaliseerd \u2014 zonder dat je er zelf naar om hoeft tekijken"}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.strong,{children:"Opsomming"})}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"Verbruik bij lage prijzen"}),"\n",(0,r.jsx)(n.li,{children:"Verkoop stroomoverschotten bij hoge prijzen"}),"\n",(0,r.jsx)(n.li,{children:"Beheers onnodige piek- en netkosten"}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.strong,{children:"Beknopt"})}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Belgisch maatwerk:"})," Gemaakt voor onze unieke markt. Helios tackelt het complexe capaciteitstarief en de netkosten volledig automatisch voor de laagste factuur"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Toekomstgarantie:"})," Halfweg andere spelregels? Helios voert vanop afstand updates uit zodat het rendement van uw investering maximaal blijft"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Vrije keuze:"})," Investeer met vertrouwen. Later van merk wisselen of uitbreiden? Helios is merkonafhankelijk. Geen weggegooid geld aan systemen die niet met elkaar praten maar \xe9\xe9n slimme verbinding die altijd werkt"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Unieke blauwdruk:"})," Geen standaardprofiel, maar sturing op basis van de hartslag van jouw woning. Helios gebruikt jouw unieke verbruik- en productie profiel"]}),"\n"]}),"\n",(0,r.jsx)(n.admonition,{title:"Download",type:"info",children:(0,r.jsxs)(n.p,{children:["Download de volledige ",(0,r.jsx)(n.a,{target:"_blank","data-noBrokenLinkCheck":!0,href:i(5414).A+"",children:"Helios Product Fiche (PDF)"})," voor gedetailleerde specificaties."]})}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.strong,{children:"TECHNISCHE FICHE"})}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Voorspellende productie modellen via \u2018Irradiance mapping\u2019"}),"\nDe productievoorspelling van Helios is gebaseerd op een deterministisch model dat lokale systeemparameters correleert met globale meteorologische instralingsgegevens.\nTijdens de inbedrijfstelling van de installatie worden de statische kenmerken van het fotovolta\xefsche systeem vastgelegd in de centrale database. Dit omvat de geometrische ori\xebntatie (azimuth), de hellingshoek van de panelen, het nominale piekvermogen (kWp) en de specifieke systeemeffici\xebntie van de gebruikte omvormer-infrastructuur. Daarnaast worden omgevingsfactoren zoals schaduwmaskers (veroorzaakt door omliggende gebouwen of vegetatie) numeriek in het model ge\xefntegreerd.\nHet systeem haalt op intermitterende basis hoog-frequente instralingsdata (irradiance) op via internationale databronnen. Deze data bieden een voorspelling van de globale horizontale instraling op de specifieke GPS-co\xf6rdinaten van de installatie. Helios hanteert een rekenmodule die deze globale data vertaalt naar een effectieve instraling op het schuine vlak van de panelen, rekening houdend met de eerder gedefinieerde systeemparameters. Dit resulteert in een kwartier-nauwkeurige productieprognose voor een horizon van 72 uur en wordt elke kwartier bijgestuurd. Deze prognose fungeert als een kritische inputvariabele voor de dagelijkse energieplanning en de aansturing van de opslagsystemen, waarbij rekening wordt gehouden met zowel directe als diffuse instralingscomponenten."]}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Marktprijs integratie met kostprijscalculatie"}),"\nDe economische optimalisatie van de energiehuishouding berust op een continue gegevensuitwisseling met de relevante energiemarkten, specifiek gericht op de Belgische context.\nHet systeem synchroniseert dagelijks met de EPEX Spot-marktdata zodra de Day-Ahead prijzen worden vrijgegeven. Deze ruwe marktdata vormen echter slechts de basis van de berekening. Helios voert een verreikende datatransformatiestap uit waarbij de spotprijzen worden gecombineerd met de specifieke contractgegevens van de eindgebruiker. Hierbij wordt elk individueel kwartier-blok verrijkt met alle bijkomende kostencomponenten die de uiteindelijke factuurprijs bepalen. Dit omvat de federale en regionale accijnzen, de bijdrage voor hernieuwbare energie, de distributienettarieven en de geldende btw-percentages.\nEen specifiek algoritme is toegewezen aan het monitoren en beheren van het Belgische capaciteitstarief. Helios analyseert de realtime data van de digitale meter via de P1-interface of een gekoppelde energiemeter om de gemiddelde kwartierpiek te berekenen. Het systeem hanteert een proactieve peak-shaving logica: wanneer de actuele belasting de ingestelde drempelwaarde nadert, worden regelbare verbruikers (zoals elektrische voertuigen of thermische bufferopslag) onmiddellijk gedownreguleerd of volledig uitgeschakeld. Deze berekening vindt continu plaats om de balans tussen maximale zelfconsumptie en minimale netkosten te handhaven."]}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Fysieke interoperabiliteit en Local-First Architectuur"}),"\nHelios wijkt fundamenteel af van cloud-gebaseerde beheersystemen door de sturingslogica volledig lokaal op de gateway uit te voeren.\nDe koppeling met assets zoals omvormers, batterij-omvormers en laadstations geschiedt via fysieke interfaces of via het lokale netwerk (LAN) middels gestandaardiseerde industri\xeble protocollen zoals Modbus RTU (via RS485) en Modbus TCP. Deze methode elimineert de afhankelijkheid van externe cloud-omgevingen van fabrikanten. Cloud-gebaseerde oplossingen vertonen vaak een hoge latentie en zijn gevoelig voor storingen in de internetverbinding of downtime van de fabrikant-servers. In dergelijke scenario's kunnen cloud-systemen geen actieve sturingscommando's meer versturen, wat leidt tot een suboptimalisatie van de installatie.\nDe Local-First architectuur van Helios garandeert dat alle kritieke beslissingsprocessen en de opslag van meetdata binnen de fysieke perimeter van de woning plaatsvinden. Dit waarborgt niet alleen de privacy van de verbruiksdata, maar zorgt er ook voor dat het systeem in milliseconden kan reageren op snelle belastingswijzigingen of variaties in de zon-intensiteit. Zelfs bij een volledige onderbreking van de internetverbinding blijft de gateway operationeel op basis van de laatst verkregen marktgegevens en de lokale sensor-input."]}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Hardware specificaties (Industrial Control Unit)"}),"\nDe hardware-unit is ontworpen voor continu gebruik in industri\xeble en residenti\xeble verdeelkasten en voldoet aan de volgende specificaties:"]}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Processor:"})," Quad-core ARM Cortex-A76, 64-bit CPU. Deze processor is specifiek geselecteerd voor de verwerking van parallelle data-streams en lokale AI-berekeningen."]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Geheugen:"})," 4GB LPDDR4X-4267 voor realtime databuffering en 64GB eMMC onboard flash-geheugen voor het besturingssysteem en lokale database-opslag."]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Behuizing:"})," Metalen CM IO Case"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Voeding:"})," 5.1V DC / 5.0A via USB-C (27W)"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Fysieke Connectiviteit:"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"1x Gigabit Ethernet (10/100/1000 Mbps), RJ45"}),"\n",(0,r.jsx)(n.li,{children:"2x USB 3.0 Type-A poorten"}),"\n"]}),"\n"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Afmetingen (B x D x H):"})," 105 mm x 75 mm x 35 mm"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Gewicht:"})," 466 g"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Omgevingscondities:"})," Operationeel temperatuurbereik van -20\xb0C tot +50\xb0C. Beschermingsklasse IP20."]}),"\n"]}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Schaalbaarheid en Systeemintegriteit"}),"\nDe software-stack van Helios is modulair opgebouwd, wat de implementatie van toekomstige updates en nieuwe apparaat-drivers mogelijk maakt zonder de kernlogica te verstoren. Het systeem ondersteunt een onbeperkt aantal assets binnen de fysieke grenzen van de hardware-capaciteit en is voorbereid op de integratie van Vehicle-to-Grid (V2G) en andere opkomende Smart Grid technologie\xebn. Alle communicatie tussen de gateway en externe monitoringservers is beveiligd middels end-to-end encryptie protocollen."]})]})}function g(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(c,{...e})}):c(e)}},5414(e,n,i){i.d(n,{A:()=>t});const t=i.p+"assets/files/Helios-technische-fiche-8a8fc1c68d59b1d2da6243857e9be96e.pdf"},8453(e,n,i){i.d(n,{R:()=>s,x:()=>o});var t=i(6540);const r={},a=t.createContext(r);function s(e){const n=t.useContext(a);return t.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:s(e.components),t.createElement(a.Provider,{value:n},e.children)}}}]);